{
  "Comment": "SEC EDGAR Bronze ingest - 4 sequential ECS Fargate tasks. Incremental by default (only CIKs that filed today); set fullRefresh:true for full scan of all ~5k NYSE/Nasdaq CIKs. Input: {\"ingestDate\": \"YYYY-MM-DD\", \"fullRefresh\": false}",
  "StartAt": "IngestTickersExchange",
  "States": {

    "IngestTickersExchange": {
      "Type": "Task",
      "Comment": "Script 01: fetch company_tickers_exchange.json snapshot (1 HTTP call, ~10k rows)",
      "Resource": "arn:aws:states:::ecs:runTask.sync",
      "TimeoutSeconds": 900,
      "HeartbeatSeconds": 300,
      "Parameters": {
        "LaunchType": "FARGATE",
        "Cluster": "arn:aws:ecs:us-east-1:690839588395:cluster/sec-edgar-cluster",
        "TaskDefinition": "sec-edgar-ingest-01",
        "NetworkConfiguration": {
          "AwsvpcConfiguration": {
            "Subnets": ["subnet-0b4b36da5bb4ac69c", "subnet-03eb778d9f7b5ae2b"],
            "SecurityGroups": ["sg-006472471fceba1e8"],
            "AssignPublicIp": "ENABLED"
          }
        },
        "Overrides": {
          "TaskRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-task-role",
          "ExecutionRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-execution-role",
          "ContainerOverrides": [{
            "Name": "ingest",
            "Command.$": "States.Array('scripts/ingest/01_ingest_tickers_exchange.py', '--date', $.ingestDate)",
            "Environment": [
              {"Name": "CLOUD_PROVIDER",     "Value": "aws"},
              {"Name": "AWS_BUCKET",         "Value": "paulananth11-sec-edgar-bronze"},
              {"Name": "AWS_DEFAULT_REGION", "Value": "us-east-1"},
              {"Name": "SEC_USER_AGENT",     "Value": "SEC EDGAR Pipeline paul.ananth@yahoo.com"}
            ]
          }]
        }
      },
      "Retry": [{
        "ErrorEquals": ["States.TaskFailed", "States.HeartbeatTimeout"],
        "IntervalSeconds": 300,
        "MaxAttempts": 1,
        "BackoffRate": 1.0
      }],
      "ResultPath": null,
      "Next": "IngestDailyIndex"
    },

    "IngestDailyIndex": {
      "Type": "Task",
      "Comment": "Script 02: fetch EDGAR daily master.idx -> write changed CIKs. FULL_REFRESH=true bypasses the index and writes all NYSE/Nasdaq CIKs.",
      "Resource": "arn:aws:states:::ecs:runTask.sync",
      "TimeoutSeconds": 900,
      "HeartbeatSeconds": 300,
      "Parameters": {
        "LaunchType": "FARGATE",
        "Cluster": "arn:aws:ecs:us-east-1:690839588395:cluster/sec-edgar-cluster",
        "TaskDefinition": "sec-edgar-ingest-02",
        "NetworkConfiguration": {
          "AwsvpcConfiguration": {
            "Subnets": ["subnet-0b4b36da5bb4ac69c", "subnet-03eb778d9f7b5ae2b"],
            "SecurityGroups": ["sg-006472471fceba1e8"],
            "AssignPublicIp": "ENABLED"
          }
        },
        "Overrides": {
          "TaskRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-task-role",
          "ExecutionRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-execution-role",
          "ContainerOverrides": [{
            "Name": "ingest",
            "Command.$": "States.Array('scripts/ingest/02_ingest_daily_index.py', '--date', $.ingestDate)",
            "Environment": [
              {"Name": "CLOUD_PROVIDER",     "Value": "aws"},
              {"Name": "AWS_BUCKET",         "Value": "paulananth11-sec-edgar-bronze"},
              {"Name": "AWS_DEFAULT_REGION", "Value": "us-east-1"},
              {"Name": "SEC_USER_AGENT",     "Value": "SEC EDGAR Pipeline paul.ananth@yahoo.com"},
              {"Name": "FULL_REFRESH",       "Value.$": "States.Format('{}', $.fullRefresh)"}
            ]
          }]
        }
      },
      "Retry": [{
        "ErrorEquals": ["States.TaskFailed", "States.HeartbeatTimeout"],
        "IntervalSeconds": 300,
        "MaxAttempts": 1,
        "BackoffRate": 1.0
      }],
      "ResultPath": null,
      "Next": "IngestSubmissions"
    },

    "IngestSubmissions": {
      "Type": "Task",
      "Comment": "Script 03: fetch submissions for changed CIKs (incremental: ~200-600 CIKs; full-refresh: ~5k, ~90 min)",
      "Resource": "arn:aws:states:::ecs:runTask.sync",
      "TimeoutSeconds": 5400,
      "HeartbeatSeconds": 300,
      "Parameters": {
        "LaunchType": "FARGATE",
        "Cluster": "arn:aws:ecs:us-east-1:690839588395:cluster/sec-edgar-cluster",
        "TaskDefinition": "sec-edgar-ingest-03",
        "NetworkConfiguration": {
          "AwsvpcConfiguration": {
            "Subnets": ["subnet-0b4b36da5bb4ac69c", "subnet-03eb778d9f7b5ae2b"],
            "SecurityGroups": ["sg-006472471fceba1e8"],
            "AssignPublicIp": "ENABLED"
          }
        },
        "Overrides": {
          "TaskRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-task-role",
          "ExecutionRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-execution-role",
          "ContainerOverrides": [{
            "Name": "ingest",
            "Command.$": "States.Array('scripts/ingest/03_ingest_submissions.py', '--date', $.ingestDate)",
            "Environment": [
              {"Name": "CLOUD_PROVIDER",     "Value": "aws"},
              {"Name": "AWS_BUCKET",         "Value": "paulananth11-sec-edgar-bronze"},
              {"Name": "AWS_DEFAULT_REGION", "Value": "us-east-1"},
              {"Name": "SEC_USER_AGENT",     "Value": "SEC EDGAR Pipeline paul.ananth@yahoo.com"},
              {"Name": "FULL_REFRESH",       "Value.$": "States.Format('{}', $.fullRefresh)"}
            ]
          }]
        }
      },
      "Retry": [{
        "ErrorEquals": ["States.TaskFailed", "States.HeartbeatTimeout"],
        "IntervalSeconds": 300,
        "MaxAttempts": 1,
        "BackoffRate": 1.0
      }],
      "ResultPath": null,
      "Next": "IngestCompanyFacts"
    },

    "IngestCompanyFacts": {
      "Type": "Task",
      "Comment": "Script 04: fetch XBRL facts for changed CIKs (incremental: ~200-600 CIKs; full-refresh: ~5k, ~90 min)",
      "Resource": "arn:aws:states:::ecs:runTask.sync",
      "TimeoutSeconds": 5400,
      "HeartbeatSeconds": 300,
      "Parameters": {
        "LaunchType": "FARGATE",
        "Cluster": "arn:aws:ecs:us-east-1:690839588395:cluster/sec-edgar-cluster",
        "TaskDefinition": "sec-edgar-ingest-04",
        "NetworkConfiguration": {
          "AwsvpcConfiguration": {
            "Subnets": ["subnet-0b4b36da5bb4ac69c", "subnet-03eb778d9f7b5ae2b"],
            "SecurityGroups": ["sg-006472471fceba1e8"],
            "AssignPublicIp": "ENABLED"
          }
        },
        "Overrides": {
          "TaskRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-task-role",
          "ExecutionRoleArn": "arn:aws:iam::690839588395:role/sec-edgar-ecs-execution-role",
          "ContainerOverrides": [{
            "Name": "ingest",
            "Command.$": "States.Array('scripts/ingest/04_ingest_companyfacts.py', '--date', $.ingestDate)",
            "Environment": [
              {"Name": "CLOUD_PROVIDER",     "Value": "aws"},
              {"Name": "AWS_BUCKET",         "Value": "paulananth11-sec-edgar-bronze"},
              {"Name": "AWS_DEFAULT_REGION", "Value": "us-east-1"},
              {"Name": "SEC_USER_AGENT",     "Value": "SEC EDGAR Pipeline paul.ananth@yahoo.com"},
              {"Name": "FULL_REFRESH",       "Value.$": "States.Format('{}', $.fullRefresh)"}
            ]
          }]
        }
      },
      "Retry": [{
        "ErrorEquals": ["States.TaskFailed", "States.HeartbeatTimeout"],
        "IntervalSeconds": 300,
        "MaxAttempts": 1,
        "BackoffRate": 1.0
      }],
      "ResultPath": null,
      "End": true
    }

  }
}
